class Solution {
public:
    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<vector<pair<int, int>>> graph(n);
        for (auto& edge : redEdges) {
            graph[edge[0]].push_back({edge[1], 0});
        }
        for (auto& edge : blueEdges) {
            graph[edge[0]].push_back({edge[1], 1});
        }

        vector<int> res(n, -1);
        res[0] = 0;
        queue<tuple<int, int, int>> q;
        q.push({0, 0, -1});
        unordered_set<string> visited;
        while (!q.empty()) {
            auto [node, step, lastColor] = q.front();
            q.pop();
            for (auto& [nextNode, color] : graph[node]) {
                if (lastColor != color && !visited.count(to_string(node) + "," + to_string(nextNode) + "," + to_string(color))) {
                    visited.insert(to_string(node) + "," + to_string(nextNode) + "," + to_string(color));
                    if (res[nextNode] == -1 || res[nextNode] > step + 1) {
                        res[nextNode] = step + 1;
                    }
                    q.push({nextNode, step + 1, color});
                }
            }
        }
        return res;
    }
};

